package com.google.gson;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.Field;
import java.lang.reflect.Method;
import java.text.DateFormat;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class GsonBuilderTest {

  private GsonBuilder gsonBuilder;

  @BeforeEach
  public void setUp() {
    gsonBuilder = new GsonBuilder();
  }

  @Test
  public void testSetDateFormat_withStyle_setsDateStyleAndNullifiesDatePattern() throws Exception {
    // Arrange
    int newDateStyle = DateFormat.MEDIUM;

    // Set initial non-null datePattern to verify it gets nullified
    Field datePatternField = GsonBuilder.class.getDeclaredField("datePattern");
    datePatternField.setAccessible(true);
    datePatternField.set(gsonBuilder, "initialPattern");

    // Act
    GsonBuilder returned = gsonBuilder.setDateFormat(newDateStyle);

    // Assert returned this for chaining
    assertSame(gsonBuilder, returned);

    // Verify dateStyle is set to newDateStyle
    Field dateStyleField = GsonBuilder.class.getDeclaredField("dateStyle");
    dateStyleField.setAccessible(true);
    int actualDateStyle = dateStyleField.getInt(gsonBuilder);
    assertEquals(newDateStyle, actualDateStyle);

    // Verify datePattern is null
    String actualDatePattern = (String) datePatternField.get(gsonBuilder);
    assertNull(actualDatePattern);
  }
}
